66	// determined. Failure to identify is not itself an error.
67	func IndexLockOwner(lockPath string) (int, error) {
68		lsof, err := exec.LookPath("lsof")
69		if err != nil {
70			return 0, nil
71		}
72		out, err := exec.Command(lsof, "-t", "--", lockPath).Output()
73		if err != nil {
74			// lsof exits non-zero when no process has the file open.
75			return 0, nil
76		}
77		s := strings.TrimSpace(string(out))
78		if s == "" {
79			return 0, nil
80		}
81		first := strings.SplitN(s, "\n", 2)[0]
82		pid, perr := strconv.Atoi(strings.TrimSpace(first))
83		if perr != nil {
84			return 0, nil
85		}
86		return pid, nil
87	}
